function initParticles(){particlesJS("particles-js",{"particles":{"number":{"value": 60, "density":{"enable": true, "value_area": 800}}, "color":{"value": "#d4a017"}, "shape":{"type": "circle"}, "opacity":{"value": 0.3, "random": true, "anim":{"enable": true, "speed": 1, "opacity_min": 0.08}}, "size":{"value": 2, "random": true}, "line_linked":{"enable": true, "distance": 150, "color": "#e6b82e", "opacity": 0.2, "width": 1}, "move":{"enable": true, "speed": 1, "direction": "none", "random": true, "out_mode": "out"}}, "interactivity":{"detect_on": "canvas", "events":{"onhover":{"enable": true, "mode": "grab"}, "onclick":{"enable": true, "mode": "push"}, "resize": true}, "modes":{"grab":{"distance": 150, "line_linked":{"opacity": 0.4}}, "push":{"particles_nb": 3}}}, "retina_detect": true});}function initAnimations(){const sidebar = document.querySelector('.sidebar');if (sidebar) sidebar.classList.add('is-loaded');const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;if (!prefersReducedMotion){const sections = document.querySelectorAll('.content-section');const sectionObserver = new IntersectionObserver((entries) =>{entries.forEach((entry) =>{if (entry.isIntersecting){entry.target.classList.add('is-visible');sectionObserver.unobserve(entry.target);}});},{threshold: 0.1, rootMargin: '0px 0px -50px 0px'});sections.forEach(s => sectionObserver.observe(s));const timelineItems = document.querySelectorAll('.timeline-item');const timelineObserver = new IntersectionObserver((entries) =>{entries.forEach((entry) =>{if (entry.isIntersecting){const items = Array.from(timelineItems);setTimeout(() => entry.target.classList.add('is-visible'), items.indexOf(entry.target) * 150);timelineObserver.unobserve(entry.target);}});},{threshold: 0.15, rootMargin: '0px 0px -30px 0px'});timelineItems.forEach(item => timelineObserver.observe(item));}else{document.querySelectorAll('.content-section, .timeline-item') .forEach(el => el.classList.add('is-visible'));}}function initScrollSpy(){const progressBar = document.getElementById('progressBar');const navDots = document.querySelectorAll('.progress-nav-dot');const sections = ['about', 'experience', 'projects', 'skills', 'contact'];function updateProgress(){const scrollTop = window.scrollY;const docHeight = document.documentElement.scrollHeight - window.innerHeight;const progress = docHeight > 0 ? (scrollTop / docHeight) * 100 : 0;if (progressBar){progressBar.style.height = Math.max(20, progress) + '%';}}const spyObserver = new IntersectionObserver((entries) =>{entries.forEach(entry =>{if (entry.isIntersecting){const id = entry.target.getAttribute('id');navDots.forEach(dot =>{dot.classList.toggle('active', dot.getAttribute('data-section') === id);});}});},{threshold: 0.3, rootMargin: '-80px 0px -60% 0px'});sections.forEach(sectionId =>{const section = document.getElementById(sectionId);if (section) spyObserver.observe(section);});navDots.forEach(dot =>{dot.addEventListener('click', () =>{const sectionId = dot.getAttribute('data-section');const target = document.getElementById(sectionId);if (target){target.scrollIntoView({behavior: 'smooth', block: 'start'});}});});if (progressBar){window.addEventListener('scroll', updateProgress,{passive: true});updateProgress();}}function initTimelineProgress(){const tlProgressBar = document.getElementById('timelineProgress');const timelineWrapper = document.querySelector('.timeline-wrapper');if (tlProgressBar && timelineWrapper){function updateTimelineProgress(){const rect = timelineWrapper.getBoundingClientRect();const timelineHeight = timelineWrapper.offsetHeight;const windowHeight = window.innerHeight;let progress = 0;if (rect.top < windowHeight && rect.bottom > 0){const scrolled = windowHeight - rect.top;progress = Math.min(Math.max(scrolled / (timelineHeight + windowHeight * 0.5) * 100, 0), 100);}tlProgressBar.style.height = progress + '%';}window.addEventListener('scroll', updateTimelineProgress,{passive: true});updateTimelineProgress();}}function initThemeSwitcher(){const root = document.documentElement;const toggleBtn = document.getElementById('theme-toggle');const themeIcon = document.getElementById('theme-icon');function updateIcon(theme){themeIcon.className = theme === 'light' ? 'fas fa-moon' : 'fas fa-sun';}function toggleTheme(){document.body.classList.add('theme-transitioning');const isLight = root.classList.toggle('light-theme');const theme = isLight ? 'light' : 'dark';localStorage.setItem('theme', theme);updateIcon(theme);setTimeout(() => document.body.classList.remove('theme-transitioning'), 350);}function initTheme(){const saved = localStorage.getItem('theme');if (saved === 'light' || (!saved && window.matchMedia('(prefers-color-scheme: light)').matches)){root.classList.add('light-theme');updateIcon('light');}}if (toggleBtn){toggleBtn.addEventListener('click', toggleTheme);}window.matchMedia('(prefers-color-scheme: light)').addEventListener('change', (e) =>{if (!localStorage.getItem('theme')){if (e.matches){root.classList.add('light-theme');updateIcon('light');}else{root.classList.remove('light-theme');updateIcon('dark');}}});initTheme();}function initMouseFollow(){const root = document.documentElement;const EASING = 0.08;let cx = window.innerWidth / 2;let cy = window.innerHeight / 2;let tx = cx;let ty = cy;if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) return;document.addEventListener('mousemove', (e) =>{tx = e.clientX;ty = e.clientY;});function animate(){cx += (tx - cx) * EASING;cy += (ty - cy) * EASING;root.style.setProperty('--mouse-x', cx + 'px');root.style.setProperty('--mouse-y', cy + 'px');requestAnimationFrame(animate);}animate();}document.addEventListener('DOMContentLoaded', () =>{console.log('🚀 CYY Portfolio Initializing...');initParticles();initAnimations();initScrollSpy();initTimelineProgress();initThemeSwitcher();initMouseFollow();console.log('✅ Portfolio initialized successfully');});